def fail(m): raise RuntimeError(m)
def load(p): return json.loads(Path(p).read_text(encoding='utf-8'))
def dump(p,v): p=Path(p); p.parent.mkdir(parents=True,exist_ok=True); p.write_text(json.dumps(v,indent=2,ensure_ascii=False)+'\n',encoding='utf-8')
def sha(p): return hashlib.sha256(Path(p).read_bytes()).hexdigest()
def esc(v): return html.escape(str(v),quote=True)

def validate(c,m):
    if c.get('missionId')!='GOALOS-PUBLIC-PROOF-MISSION-006' or c.get('sequence')!=6: fail('wrong Mission 006 identity')
    if c.get('status')!='PROTOCOL_PUBLISHED_AWAITING_ONE_FEDERATION_PROVEN_COMMONWEALTH': fail('unexpected Mission 006 status')
    if len(c.get('proofRoute',[]))!=44 or len({x['contractName'] for x in c['proofRoute']})!=44: fail('Mission 006 requires 44 distinct proof-route contracts')
    if len(c.get('validators',[]))!=7 or len(c.get('continuityTrial',{}).get('eras',[]))!=7: fail('Mission 006 requires seven eras and seven validators')
    if sum(int(x.get('share',0)) for x in c.get('settlement',[]))!=100: fail('settlement must total 100')
    b=c.get('missionBudget',{})
    if b.get('modelAndToolchainGenerations')!=8 or b.get('cryptographicEpochs')!=3 or b.get('challengeWindowHours')!=720: fail('Mission 006 budget mismatch')
    if c.get('mission7',{}).get('status')!='HORIZON_ONLY_NOT_YET_AUTHORIZED': fail('Mission 007 must remain horizon only')
    if m.get('chainId')!=1 or m.get('canonicalAgialpha','').lower()!=CANONICAL.lower(): fail('Mainnet identity mismatch')
    if m.get('goalosCreatedContractCount')!=48 or m.get('verification',{}).get('verified')!=48 or m.get('verification',{}).get('failed')!=0: fail('Mainnet verification mismatch')
    if m.get('phaseBGrantCount')!=14 or m.get('postcheck',{}).get('status')!='PASSED': fail('Mainnet configuration mismatch')
    names={x['name'] for x in m.get('contracts',[])}
    missing=[x['contractName'] for x in c['proofRoute'] if x['contractName'] not in names]
    if missing: fail('unknown proof-route contracts: '+', '.join(missing))
    blob=json.dumps(c,ensure_ascii=False).lower()
    for x in FORBIDDEN:
        if x in blob: fail('prohibited public reference: '+x)

def emblem():
    nodes=[(250,45,'GENESIS'),(430,153,'SUCCESSION'),(430,347,'MIGRATION'),(250,455,'FUTURE'),(70,347,'ARCHIVE'),(70,153,'CHALLENGE')]
    n=''.join(f'<g><circle cx="{x}" cy="{y}" r="43"/><text x="{x}" y="{y+4}" text-anchor="middle">{t}</text></g>' for x,y,t in nodes)
    rays=''.join(f'<path d="M250 250 L{x} {y}"/>' for x,y,_ in nodes)
    return f'''<svg class="lh-emblem" viewBox="0 0 500 500" role="img" aria-label="Long Horizon continuity constellation"><defs><radialGradient id="core"><stop stop-color="#fff"/><stop offset=".35" stop-color="#f2cb70"/><stop offset=".7" stop-color="#b8d9ff"/><stop offset="1" stop-color="#7d6bf2"/></radialGradient><linearGradient id="line"><stop stop-color="#f2cb70"/><stop offset=".55" stop-color="#b8d9ff"/><stop offset="1" stop-color="#9f8cff"/></linearGradient><filter id="glow"><feGaussianBlur stdDeviation="5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><circle class="orbit" cx="250" cy="250" r="222"/><circle class="orbit o2" cx="250" cy="250" r="165"/><circle class="orbit o3" cx="250" cy="250" r="112"/><g class="rays">{rays}</g><g class="nodes">{n}</g><g filter="url(#glow)"><circle cx="250" cy="250" r="78" fill="url(#core)"/><text class="coretext" x="250" y="226" text-anchor="middle">THE</text><text class="coretext" x="250" y="251" text-anchor="middle">LONG</text><text class="coretext" x="250" y="276" text-anchor="middle">HORIZON</text><text class="m6" x="250" y="311" text-anchor="middle">M6</text></g><text class="motto" x="250" y="495" text-anchor="middle">PROVENANCE · CONSENT · EXIT · CONTINUITY</text></svg>'''

