def route_html(c,m):
    by={x['name']:x for x in m['contracts']}; out=[]
    for x in c['proofRoute']:
        d=by[x['contractName']]; search=' '.join([x['stage'],x['contractName'],x['purpose'],d['address']]).lower()
        out.append(f'''<article class="route-item" data-search="{esc(search)}"><small>{x['sequence']:02d} · {esc(x['stage'])}</small><h3>{esc(x['contractName'])}</h3><p>{esc(x['purpose'])}</p><a href="{esc(d['etherscanUrl'])}" target="_blank" rel="noopener">Inspect {esc(d['address'][:8]+'…'+d['address'][-6:])}</a></article>''')
    return ''.join(out)

def page(c,m):
    laws=''.join(f'<article class="law">{esc(x)}</article>' for x in c['constitution'])
    arch=''.join(f'''<article class="card {'treatment' if x['id'].startswith('TREATMENT') else ''}"><small>{esc(x['id'].replace('_',' '))}</small><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in c['controlArchitectures'])
    eras=''.join(f'''<article class="era"><b>{esc(x['id'])}</b><div><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></div></article>''' for x in c['continuityTrial']['eras'])
    stack=''.join(f'''<article><strong>{i:02d}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for i,x in enumerate(c['continuityStack'],1))
