def replace_marked(t,s,e,r): return re.sub(re.escape(s)+r'.*?'+re.escape(e),r,t,flags=re.S)
def inject_home(p):
 p=Path(p); raw=p.read_text(); st=home_style(); sec=home_section()
 raw=replace_marked(raw,STYLE_START,STYLE_END,st) if STYLE_START in raw else raw.replace('</head>',st+'\n</head>',1)
 if START in raw: raw=replace_marked(raw,START,END,sec)
 elif M5_END in raw: raw=raw.replace(M5_END,M5_END+'\n'+sec,1)
 else: fail('Mission 005 homepage marker not found')
 p.write_text(raw)

def promote_m5(p):
 p=Path(p); raw=p.read_text()
 active=f'''{PROMO_START}<article class="ia-horizon"><strong>PUBLIC PROOF MISSION 006 · NOW PUBLISHED</strong><h2 style="font-size:clamp(2rem,4vw,3.6rem);margin:.7rem 0">The Long Horizon</h2><p style="font-size:1.12rem;line-height:1.7;color:#19303c">Mission 006 publishes the protocol for provenance-preserving succession, cryptographic migration, archival recovery, environmental adaptation, public challenge, human ratification, exit, fork, rollback, and final disposition.</p><p><a class="ia-btn primary" href="proof-mission-006.html">Enter Mission 006</a></p></article>{PROMO_END}'''
 if PROMO_START in raw: raw=replace_marked(raw,PROMO_START,PROMO_END,active)
 else:
  raw,n=re.subn(r'<article class="ia-horizon"><strong>MISSION 006 HORIZON</strong>.*?</article>',active,raw,count=1,flags=re.S)
  if n!=1: fail('Mission 005 horizon not found')
 p.write_text(raw)

