 ap=argparse.ArgumentParser(); ap.add_argument('--site',default='site'); ap.add_argument('--content',default='content/proof-mission-006-long-horizon.json'); ap.add_argument('--mainnet',default='data/mainnet/v4.4.0-mainnet-2026-06-21.json'); a=ap.parse_args()
 site=Path(a.site); cp=Path(a.content); mp=Path(a.mainnet); c=load(cp); m=load(mp); validate(c,m)
